"""
compiler.py — ONNX Wave-Math Graph Compiler

Exports a frozen, hardware-optimised ONNX execution graph that computes
pairwise wave interference scores between a query wavepacket and a batch
of database wavepackets.

Why split real / imaginary instead of native complex tensors?
--------------------------------------------------------------
Production ONNX runtimes do not natively optimise complex float tensors.
By decomposing each complex dimension into a real and an imaginary lane
we reduce to pure float32 MatMul / Add — operators that every ONNX
execution provider (CPU, CUDA, OpenVINO, CoreML) accelerates natively.

Tensor geometry
---------------
For embedding dimension N, every wavepacket is encoded as a flat float32
vector of length 2N:
    indices [0 … N-1]   -> Real lane  =  A·cos(phi)
    indices [N … 2N-1]  -> Imag lane  =  A·sin(phi)

Graph inputs
    query    : (2N,)     -- single query wavepacket
    db_batch : (M, 2N)   -- M candidate wavepackets (M is dynamic)

Graph output
    scores   : (M,)      -- per-candidate interference score

Signal formula (per candidate j)
    Signal_j = Σ_k [ Real_Q[k]·Real_DB[j,k] + Imag_Q[k]·Imag_DB[j,k] ]

    Derivation: cos(φ_Q - φ_V) = cos(φ_Q)cos(φ_V) + sin(φ_Q)sin(φ_V)
    so substituting Real=A·cos(φ), Imag=A·sin(φ) gives the + sign.

Operator set
    Slice, MatMul, Add  -- pure onnx.helper, no torch dependency.
"""

from __future__ import annotations

import math
from pathlib import Path

import numpy as np

DEFAULT_OUTPUT = "resonance_engine.onnx"


def compile_resonance_graph(
    embedding_dim: int,
    output_path: str | Path = DEFAULT_OUTPUT,
    opset: int = 17,
) -> Path:
    """
    Build and export the wave-interference ONNX computation graph.

    Uses pure onnx.helper — no torch dependency required.

    Parameters
    ----------
    embedding_dim : int
        Dimension N of the upstream (real-valued) embedding vectors.
        The exported graph will accept tensors of width 2·N.
    output_path   : path to write the .onnx file.
    opset         : ONNX opset version (default 17).

    Returns
    -------
    Resolved Path of the written .onnx file.
    """
    try:
        import onnx
        from onnx import helper, TensorProto, numpy_helper
    except ImportError as exc:
        raise ImportError(
            "onnx is required for graph compilation: pip install onnx"
        ) from exc

    output_path = Path(output_path)
    N = embedding_dim

    # ── Input / output value-info ──────────────────────────────────────────
    query_vi    = helper.make_tensor_value_info("query",    TensorProto.FLOAT, [2 * N])
    db_batch_vi = helper.make_tensor_value_info("db_batch", TensorProto.FLOAT, [None, 2 * N])
    scores_vi   = helper.make_tensor_value_info("scores",   TensorProto.FLOAT, [None])

    # ── Slice constants (stored as graph initializers) ────────────────────
    starts_0  = numpy_helper.from_array(np.array([0],     dtype=np.int64), name="starts_0")
    ends_N    = numpy_helper.from_array(np.array([N],     dtype=np.int64), name="ends_N")
    starts_N  = numpy_helper.from_array(np.array([N],     dtype=np.int64), name="starts_N")
    ends_2N   = numpy_helper.from_array(np.array([2 * N], dtype=np.int64), name="ends_2N")
    axes_0    = numpy_helper.from_array(np.array([0],     dtype=np.int64), name="axes_0")
    axes_1    = numpy_helper.from_array(np.array([1],     dtype=np.int64), name="axes_1")

    # ── Graph nodes ────────────────────────────────────────────────────────
    # Slice query real lane:  query[0:N]  -> real_q  (N,)
    node_slice_q_real = helper.make_node(
        "Slice",
        inputs=["query", "starts_0", "ends_N", "axes_0"],
        outputs=["real_q"],
    )

    # Slice query imag lane:  query[N:2N]  -> imag_q  (N,)
    node_slice_q_imag = helper.make_node(
        "Slice",
        inputs=["query", "starts_N", "ends_2N", "axes_0"],
        outputs=["imag_q"],
    )

    # Slice db real lane:  db_batch[:, 0:N]  -> real_db  (M, N)
    node_slice_db_real = helper.make_node(
        "Slice",
        inputs=["db_batch", "starts_0", "ends_N", "axes_1"],
        outputs=["real_db"],
    )

    # Slice db imag lane:  db_batch[:, N:2N]  -> imag_db  (M, N)
    node_slice_db_imag = helper.make_node(
        "Slice",
        inputs=["db_batch", "starts_N", "ends_2N", "axes_1"],
        outputs=["imag_db"],
    )

    # real_scores = real_db @ real_q  ->  (M,)
    node_real_mm = helper.make_node(
        "MatMul",
        inputs=["real_db", "real_q"],
        outputs=["real_scores"],
    )

    # imag_scores = imag_db @ imag_q  ->  (M,)
    node_imag_mm = helper.make_node(
        "MatMul",
        inputs=["imag_db", "imag_q"],
        outputs=["imag_scores"],
    )

    # scores = real_scores + imag_scores  ->  (M,)
    # cos(phi_Q - phi_DB) = cos(phi_Q)*cos(phi_DB) + sin(phi_Q)*sin(phi_DB)
    node_sub = helper.make_node(
        "Add",
        inputs=["real_scores", "imag_scores"],
        outputs=["scores"],
    )

    # ── Assemble graph ─────────────────────────────────────────────────────
    graph = helper.make_graph(
        nodes=[
            node_slice_q_real,
            node_slice_q_imag,
            node_slice_db_real,
            node_slice_db_imag,
            node_real_mm,
            node_imag_mm,
            node_sub,
        ],
        name="wave_interference",
        inputs=[query_vi, db_batch_vi],
        outputs=[scores_vi],
        initializer=[starts_0, ends_N, starts_N, ends_2N, axes_0, axes_1],
    )

    model = helper.make_model(
        graph,
        opset_imports=[helper.make_opsetid("", opset)],
    )
    model.ir_version = 8

    onnx.checker.check_model(model)
    onnx.save(model, str(output_path))

    return output_path.resolve()


def wavepack_encode(
    amplitude: np.ndarray,
    phi: float,
) -> np.ndarray:
    """
    Encode a single embedding + phase angle into a 2N flat wavepacket.

    Parameters
    ----------
    amplitude : ndarray of shape (N,) -- static semantic coordinates.
    phi       : float -- phase angle in [-pi, pi].

    Returns
    -------
    ndarray of shape (2N,) -- [A·cos(phi)..., A·sin(phi)...]
    """
    cos_phi = math.cos(phi)
    sin_phi = math.sin(phi)
    return np.concatenate([
        amplitude * cos_phi,   # real lane
        amplitude * sin_phi,   # imaginary lane
    ]).astype(np.float32)


def wavepack_encode_batch(
    amplitudes: np.ndarray,
    phis: np.ndarray,
) -> np.ndarray:
    """
    Vectorised batch encoding for M embeddings.

    Parameters
    ----------
    amplitudes : ndarray of shape (M, N).
    phis       : ndarray of shape (M,) -- one phase per row.

    Returns
    -------
    ndarray of shape (M, 2N).
    """
    cos_phi = np.cos(phis)[:, None]   # (M, 1)
    sin_phi = np.sin(phis)[:, None]   # (M, 1)
    real_lane = amplitudes * cos_phi  # (M, N)
    imag_lane = amplitudes * sin_phi  # (M, N)
    return np.concatenate([real_lane, imag_lane], axis=1).astype(np.float32)
